SELECT AVG(voter_turnout) AS avg_turnout
FROM election_data
WHERE dem_vote > rep_vote;

SELECT year, SUM(oct_rate) AS total_october_voters
FROM election_data
GROUP BY year;

SELECT AVG(voter_turnout) AS average_voter_turnout
FROM election_data
WHERE dem_vote > rep_vote;

SELECT SUM(dem_vote) AS total_democratic_support
FROM election_data
WHERE year = 2020 AND dem_vote > rep_vote;

SELECT AVG(voter_turnout) AS average_voter_turnout
FROM election_data
WHERE year = 2020;

SELECT AVG(voter_turnout) AS average_voter_turnout
FROM election_data
WHERE dem_vote > rep_vote AND (dem_vote + rep_vote) >= 10000;

SELECT AVG(voter_turnout) AS average_voter_turnout
FROM election_data
WHERE ABS(dem_vote - rep_vote) > 10000;
